Server skips headers and never send them, so the next one will never be valid since chain lags with single/multiple headers. I have tested it with simple nodeJs script with two servers (testnetnode.arihanc.com&testnet.hsmiths.com), watched them at the same time, the first server sent the headers respectively while the second sometimes hops. Shouldn't the server saves last header sent to clients and start within? 

Would this happen on MainNet!?

Below is the script along with attached screenshots from my cmd shell.
```
var net = require('net');

var client = new net.Socket();
client.connect(53011, 'testnet.hsmiths.com', function() {
console.log('Connected');
client.write("{\"id\":0,\"method\":\"server.version\",\"params\":[\"2.7.11\"]}\n");
client.write("{ \"id\": 3, \"method\": \"blockchain.headers.subscribe\", \"params\": []}\n");
client.write("{ \"id\": 0, \"method\": \"blockchain.numblocks.subscribe\", \"params\": []}\n");
setInterval(function(){
	client.write("{\"id\":0,\"method\":\"server.version\",\"params\":[\"2.7.11\"]}\n");
},55000);
});


client.on('data', function(data) {
console.log(data.toString());
});


client.on('close', function() {
console.log('Connection closed');
});
```
